const items = $input.all();
const body = items[0].json.body;

const organizationId = body.organization_id;
const userMaxId = body.user_max_id;
const question = body.question;

return [{
  json: {
    organizationId,
    userMaxId,
    question
  }
}];

const crypto = require('crypto');
const data = $input.first().json;
const question = data.question;
const organizationId = data.organizationId;
const collectionName = `org_${organizationId}`;

// --- GigaChat Auth ---
const clientId = $env.GIGACHAT_CLIENT_ID;
const clientSecret = $env.GIGACHAT_CLIENT_SECRET;
const basicAuth = Buffer.from(`${clientId}:${clientSecret}`).toString('base64');

const authResponse = await fetch('https://ngw.devices.sberbank.ru:9443/api/v2/oauth', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/x-www-form-urlencoded',
    'Authorization': `Basic ${basicAuth}`,
    'RqUID': crypto.randomUUID()
  },
  body: 'scope=GIGACHAT_API_PERS'
});
const authData = await authResponse.json();
const token = authData.access_token;

// --- Embed Question ---
const embResponse = await fetch('https://gigachat.devices.sberbank.ru/api/v1/embeddings', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${token}`
  },
  body: JSON.stringify({
    model: 'Embeddings',
    input: [question]
  })
});
const embData = await embResponse.json();
const queryVector = embData.data[0].embedding;

// --- Qdrant Search ---
const searchResponse = await fetch(`http://qdrant:6333/collections/${collectionName}/points/search`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    vector: queryVector,
    limit: 5,
    with_payload: true
  })
});
const searchData = await searchResponse.json();
const results = searchData.result || [];

const sourceChunks = results.map(r => ({
  document_id: r.payload.document_id,
  chunk_index: r.payload.chunk_index,
  content: r.payload.content,
  score: r.score
}));

const context = sourceChunks.map((c, i) => `[${i + 1}] ${c.content}`).join('\n\n');

// --- GigaChat Chat Completion ---
const chatResponse = await fetch('https://gigachat.devices.sberbank.ru/api/v1/chat/completions', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${token}`
  },
  body: JSON.stringify({
    model: 'GigaChat',
    temperature: 0.3,
    messages: [
      {
        role: 'system',
        content: 'You are a helpful assistant that answers questions based on the provided context from the organization knowledge base. If the context does not contain enough information to answer, say so. Always reference which context fragments you used.'
      },
      {
        role: 'user',
        content: `Context:\n${context}\n\nQuestion: ${question}`
      }
    ]
  })
});
const chatData = await chatResponse.json();
const answer = chatData.choices[0].message.content;

return [{
  json: {
    organizationId,
    userMaxId: data.userMaxId,
    question,
    answer,
    sourceChunks
  }
}];

